#region ── Build pipeline ─────────────────────────────────────────────────────

function Start-SAROSBuild {
    $script:StartTime = Get-Date
    $tot = 12
    Write-Banner "SAROS v$($script:Ver) — Secure Autonomous Recovery OS"

    $interactive = -not $Silent

    # ── Resolve settings ─────────────────────────────────────────────────
    $ed = $Edition  ?? ($interactive ? (Read-Choice 'Windows edition' @('Pro','Enterprise') 'Pro') : $null)
    if (-not $ed) { throw 'Edition required. Pass -Edition or run without -Silent.' }
    $edK = ($ed -in 'Enterprise','ENT','ent') ? 'ENT' : 'PRO'

    $lang = $Language ?? ($interactive ? ($null) : $null)
    if (-not $lang -and $interactive) {
        $picked = Read-Searchable 'Setup language' (($script:Locales | Sort-Object N).N) 'English (United Kingdom)'
        $lang = ($script:Locales | Where-Object N -EQ $picked).L
    }
    $lr = $script:Locales | Where-Object L -EQ $lang
    if (-not $lr) { throw "Unknown locale: $lang" }

    $tz = $TimeZone ?? ($interactive ? ($null) : $null)
    if (-not $tz -and $interactive) {
        $tzD = $script:TZList | ForEach-Object { ($_ -split '\|')[1] }
        $picked = Read-Searchable 'Time zone' $tzD '(UTC) Dublin - Edinburgh - Lisbon - London'
        $tz = ($script:TZList | Where-Object { ($_ -split '\|')[1] -eq $picked } | ForEach-Object { ($_ -split '\|')[0] })
    }
    if (-not ($script:TZList | Where-Object { ($_ -split '\|')[0] -eq $tz })) { throw "Unknown timezone: $tz" }

    $pt = $PAWType    ?? ($interactive ? (Read-Choice 'PAW type' @('BOOTSTRAP','CLOUD') 'BOOTSTRAP') : 'BOOTSTRAP')
    $ot = $OutputType ?? ($interactive ? (Read-Choice 'Output type' @('ISO','USB') 'ISO') : 'ISO')
    $sp = $SourcePath ?? ($interactive ? (Read-FolderPath 'Source folder (must contain ISO subfolder)' -MustExist) : $null)
    if (-not $sp -or -not (Test-Path $sp)) { throw "Source path required and must exist: $sp" }
    $bp = $BuildPath  ?? ($interactive ? (Read-FolderPath 'Build output folder (will be created)') : $null)
    if (-not $bp -or -not [IO.Path]::IsPathRooted($bp)) { throw "Absolute build path required: $bp" }
    if (Test-Path $bp) { throw "Build path already exists: $bp" }

    # Full build requires Windows (DISM, WIM servicing, registry hives)
    if (-not $script:OnWindows) {
        throw "Full media build requires Windows (DISM, WIM servicing, registry operations). Use -AnswerFileOnly on $($script:Platform)."
    }

    $key = $script:KMSKeys[$edK]

    Write-Host "`n  SAROS build configuration" -ForegroundColor White
    foreach ($line in @("    Edition  : $edK","    Language : $($lr.L) - $($lr.N)","    TimeZone : $tz","    PAW Type : $pt","    Output   : $ot","    Source   : $sp","    Build    : $bp")) { Write-Host $line -ForegroundColor Gray }
    Write-Host ''
    if ($interactive) { $go = Read-Host '  Proceed? (Y/n)'; if ($go -and $go -notin 'Y','y','yes') { return } }

    # ── 1 — Create folder structure ──────────────────────────────────────
    Write-Step 1 $tot 'Creating build folder structure'
    foreach ($d in 'DISM-Offline','ISO-Files','ISO-Source','ISO-Temp','ISO-Temp\split','SAROS','SAROS\Firewall-Rules','SAROS\W11Apps') {
        New-Item "$bp\$d" -ItemType Directory -Force | Out-Null
    }
    Set-Location $bp

    # ── 2 — Write embedded hardening files to disk ───────────────────────
    Write-Step 2 $tot 'Staging hardening content'
    Write-RegFile "$bp\SAROS\BlackHoleProxy.reg"  $script:Content.BlackHoleProxy
    Write-RegFile "$bp\SAROS\FW.reg"              $script:Content.FirewallProfiles
    Write-RegFile "$bp\SAROS\FWRules.reg"         $script:Content.FirewallRulesReg
    $script:Content.FirewallRulesPS       | Set-Content "$bp\SAROS\Firewall-Rules\FwRules.ps1" -Encoding UTF8
    $script:Content.SetupComplete         | Set-Content "$bp\SAROS\SetupComplete.cmd" -Encoding ASCII
    $script:Content.W10Apps               | Set-Content "$bp\SAROS\W10Apps.txt" -Encoding UTF8
    $script:Content.W11Apps               | Set-Content "$bp\SAROS\W11Apps.txt" -Encoding UTF8
    $script:Content.W11AppRemovalScript   | Set-Content "$bp\SAROS\W11Apps\W11AppRemoval.ps1" -Encoding UTF8
    # Also write the app list for the first-boot script
    $script:Content.W11Apps               | Set-Content "$bp\SAROS\W11Apps\W11Apps.txt" -Encoding UTF8

    # ── 3 — Mount ISO, find edition ──────────────────────────────────────
    Write-Step 3 $tot 'Mounting ISO and locating edition'
    if (-not (Test-Path "$sp\iso\*.iso")) { throw "No .iso found in $sp\iso\" }
    $isoFile = (Get-ChildItem "$sp\iso\*.iso" | Select-Object -First 1).FullName
    $script:MountedISO = $isoFile
    $drv = (Mount-DiskImage -ImagePath $isoFile -PassThru | Get-Volume).DriveLetter
    $wimSrc = "${drv}:\sources\install.wim"
    if (-not (Test-Path $wimSrc)) { throw 'No install.wim in ISO.' }

    $images = Get-WindowsImage -ImagePath $wimSrc
    $match = $images | Where-Object {
        ($_.ImageName -match 'Windows 1[01] Enterprise' -and $edK -eq 'ENT') -or
        ($_.ImageName -match 'Windows 1[01] Pro$'       -and $edK -eq 'PRO')
    } | Select-Object -First 1
    if (-not $match) { throw "$edK not found in ISO. Available: $(($images.ImageName) -join ', ')" }
    $wv = ($match.ImageName -match '11') ? '11' : '10'
    Write-Log "Matched: $($match.ImageName) (index $($match.ImageIndex), Win $wv)"

    # ── 4 — Copy ISO contents, export edition ────────────────────────────
    Write-Step 4 $tot 'Copying ISO contents and exporting edition'
    Copy-Item "${drv}:\*" '.\ISO-Files' -Recurse -Force
    Export-WindowsImage -SourceImagePath '.\ISO-Files\sources\install.wim' -SourceIndex $match.ImageIndex `
        -DestinationImagePath '.\ISO-Temp\export.wim' -DestinationName $match.ImageName -CompressionType Max
    Move-Item '.\ISO-Files\sources\install.wim' '.\ISO-Temp\install-multi.wim'
    Move-Item '.\ISO-Temp\export.wim' '.\ISO-Files\sources\install.wim' -Force

    # ── 5 — Mount WIM ────────────────────────────────────────────────────
    Write-Step 5 $tot 'Mounting WIM image'
    Mount-WindowsImage -ImagePath '.\ISO-Files\sources\install.wim' -Index 1 -Path '.\DISM-Offline'
    $script:WIMMounted = $true
    foreach ($d in 'SAROS\Firewall-Rules','SAROS\W11Apps','Windows\Setup\Scripts') {
        New-Item ".\DISM-Offline\$d" -ItemType Directory -Force -ErrorAction SilentlyContinue | Out-Null
    }

    # ── 6 — Inject content ───────────────────────────────────────────────
    Write-Step 6 $tot 'Injecting drivers, updates, and Autopilot config'
    if (Test-Path "$sp\Drivers\*")       { Write-Log 'Drivers';  Add-WindowsDriver  -Path '.\DISM-Offline' -Driver "$sp\Drivers" -Recurse }
    if (Test-Path "$sp\ssu\*")           { Write-Log 'SSU';      Add-WindowsPackage -PackagePath "$sp\ssu" -Path '.\DISM-Offline' }
    if (Test-Path "$sp\Updates\*")       { Write-Log 'Updates';  Add-WindowsPackage -PackagePath "$sp\Updates" -Path '.\DISM-Offline' }
    if ((Test-Path "$sp\Autopilot\*.json") -and $pt -eq 'CLOUD') {
        Write-Log 'Autopilot config'
        $apD = '.\DISM-Offline\Windows\Provisioning\Autopilot'
        New-Item $apD -ItemType Directory -Force -ErrorAction SilentlyContinue | Out-Null
        Copy-Item "$sp\Autopilot\*.json" $apD -Force
    }

    # ── 7 — Registry hardening ───────────────────────────────────────────
    Write-Step 7 $tot 'Applying registry hardening and firewall policy'
    Mount-Hive 'USR' '.\DISM-Offline\Users\Default\NTUSER.DAT'
    & reg.exe import "$bp\SAROS\BlackHoleProxy.reg" 2>$null | Out-Null
    if ($wv -eq '11') { New-ItemProperty -LiteralPath 'HKLM:\USR\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced' -Name 'TaskbarDa' -Value 0 -Force -EA SilentlyContinue | Out-Null }
    Dismount-Hive 'USR'

    Mount-Hive 'SYS' '.\DISM-Offline\Windows\System32\config\SYSTEM'
    & reg.exe import "$bp\SAROS\FW.reg"      2>$null | Out-Null
    & reg.exe import "$bp\SAROS\FWRules.reg"  2>$null | Out-Null
    Copy-Item "$bp\SAROS\Firewall-Rules\FwRules.ps1" '.\DISM-Offline\SAROS\Firewall-Rules\FwRules.ps1' -Force
    Dismount-Hive 'SYS'

    Mount-Hive 'SOFT' '.\DISM-Offline\Windows\System32\config\SOFTWARE'
    $ro = 'HKLM:\SOFT\Microsoft\Windows\CurrentVersion\RunOnce'
    New-ItemProperty -Path $ro -Name 'SAROS-FirewallRules' -PropertyType String -Force `
        -Value 'powershell.exe -ExecutionPolicy Bypass -File C:\SAROS\Firewall-Rules\FWrules.ps1' | Out-Null
    if ($wv -eq '11') {
        Copy-Item "$bp\SAROS\W11Apps\*" '.\DISM-Offline\SAROS\W11Apps\' -Force
        New-ItemProperty -Path $ro -Name 'SAROS-RemoveW11Apps' -PropertyType String -Force `
            -Value 'powershell.exe -ExecutionPolicy Bypass -File C:\SAROS\W11Apps\W11AppRemoval.ps1' | Out-Null
    }
    Dismount-Hive 'SOFT'

    Copy-Item "$bp\SAROS\SetupComplete.cmd" '.\DISM-Offline\Windows\Setup\Scripts\SetupComplete.cmd' -Force

    # ── 8 — Remove bloatware ─────────────────────────────────────────────
    Write-Step 8 $tot 'Removing provisioned bloatware'
    $appFile = ($wv -eq '10') ? "$bp\SAROS\W10Apps.txt" : "$bp\SAROS\W11Apps.txt"
    foreach ($app in (Get-Content $appFile)) {
        Get-AppxProvisionedPackage -Path '.\DISM-Offline' | Where-Object DisplayName -EQ $app |
            Remove-AppxProvisionedPackage -EA SilentlyContinue | Out-Null
    }

    # WinRE resize
    $wre = '.\DISM-Offline\Windows\System32\Recovery\winre.wim'
    if ((Test-Path $wre) -and (Get-Item $wre).Length -gt 400MB) {
        Write-Log 'Shrinking WinRE'; Export-WindowsImage -SourceImagePath $wre -SourceIndex 1 -DestinationImagePath "${wre}.new"
        Remove-Item $wre; Rename-Item "${wre}.new" 'winre.wim'
    }

    # ── 9 — Answer file ──────────────────────────────────────────────────
    Write-Step 9 $tot "Generating $pt answer file"
    New-AnswerFile -Lang $lr.L -KB $lr.K -TZ $tz -Key $key -Ed $edK -Type $pt -Dir '.\ISO-Files'

    # ── 10 — Dismount and recompress ─────────────────────────────────────
    Write-Step 10 $tot 'Dismounting and recompressing WIM'
    & dism.exe /Image:.\DISM-Offline /Cleanup-Image /StartComponentCleanup /ResetBase 2>&1 | Where-Object { $_ -match '\S' } | ForEach-Object { Write-Log $_ }
    Dismount-WindowsImage -Path '.\DISM-Offline' -Save; $script:WIMMounted = $false

    $destName = "Windows $wv $(($edK -eq 'ENT') ? 'Enterprise' : 'Pro')"
    Export-WindowsImage -SourceImagePath '.\ISO-Files\sources\install.wim' -SourceIndex 1 -DestinationImagePath '.\ISO-Temp\recomp.wim' -DestinationName $destName -CompressionType Max
    if ((Get-Item '.\ISO-Temp\recomp.wim').Length -lt (Get-Item '.\ISO-Files\sources\install.wim').Length) {
        Move-Item '.\ISO-Files\sources\install.wim' '.\ISO-Temp\install-pre.wim'; Move-Item '.\ISO-Temp\recomp.wim' '.\ISO-Files\sources\install.wim' -Force
    } else { Remove-Item '.\ISO-Temp\recomp.wim' }

    Dismount-DiskImage -ImagePath $script:MountedISO -EA SilentlyContinue | Out-Null; $script:MountedISO = $null

    if ((Get-Item '.\ISO-Files\sources\install.wim').Length -gt 4GB) {
        Write-Log 'Splitting WIM for FAT32'; Move-Item '.\ISO-Files\sources\install.wim' '.\ISO-Temp\split\'
        Split-WindowsImage -ImagePath '.\ISO-Temp\split\install.wim' -SplitImagePath '.\ISO-Temp\split\install.swm' -FileSize 4096
        Copy-Item '.\ISO-Temp\split\*.swm' '.\ISO-Files\sources\'
    }

    # ── 11 — Create output ───────────────────────────────────────────────
    $pfx = ($pt -eq 'CLOUD') ? 'C' : 'B'
    if ($ot -eq 'USB') {
        Write-Step 11 $tot 'Writing to USB drive'
        do {
            $usbAll = Get-Disk | Where-Object { $_.BusType -eq 'USB' -and $_.Size -gt 7GB -and $_.Size -lt 32GB }
            if (-not $usbAll) { throw 'No USB drives found (8-32 GB).' }
            $usbDisk = if (($usbAll | Measure-Object).Count -gt 1 -and -not ($AutoConfirmUSB -or $Silent)) {
                $usbAll | ForEach-Object { Write-Host "    Disk $($_.Number): $($_.FriendlyName) - $([math]::Round($_.Size/1GB,1)) GB" -ForegroundColor Gray }
                $usbAll | Where-Object Number -EQ (Read-Host '  Disk number')
            } else { $usbAll | Select-Object -First 1 }
            if (-not $usbDisk) { throw 'No USB disk selected.' }
            if (-not ($Silent -or $AutoConfirmUSB)) { Write-Host "  ALL DATA on Disk $($usbDisk.Number) ($($usbDisk.FriendlyName)) will be ERASED." -ForegroundColor Red; if ((Read-Host '  Type YES') -ne 'YES') { throw 'Cancelled.' } }
            $usbDisk | Clear-Disk -RemoveData -Confirm:$false
            if ($usbDisk.PartitionStyle -eq 'RAW') { $usbDisk | Initialize-Disk -PartitionStyle GPT } else { $usbDisk | Set-Disk -PartitionStyle GPT }
            $part = $usbDisk | New-Partition -UseMaximumSize -AssignDriveLetter
            Format-Volume -Partition $part -FileSystem FAT32 -NewFileSystemLabel 'SAROS' -Confirm:$false | Out-Null
            Copy-Item '.\ISO-Files\*' "$($part.DriveLetter):\" -Recurse -Force
            Write-Log "USB $($part.DriveLetter): complete"
            if ($Silent) { break }
            $again = Read-Host '  Write another USB? (y/N)'
        } while ($again -in 'y','Y','yes')
    } else {
        Write-Step 11 $tot 'Creating bootable ISO (embedded oscdimg)'
        $osc = Expand-EmbeddedOscdimg
        $outISO = "SAROS-${pfx}${edK}${wv}-$($lr.L)-$(Get-Date -f MMyyyy).iso"
        $efi = '.\ISO-Files\efi\microsoft\boot\efisys.bin'
        if (-not (Test-Path $efi)) { throw "efisys.bin not found — is this a valid UEFI Windows ISO?" }
        & $osc -b"$((Resolve-Path $efi).Path)" -pEF -u1 -udfver102 "$((Resolve-Path '.\ISO-Files').Path)" "$outISO" 2>&1 |
            Where-Object { $_ -match '\S' } | ForEach-Object { Write-Log $_ }
        Get-FileHash $outISO | Out-File '.\HASHES.txt' -Force
        Write-Log "ISO: $bp\$outISO"
        if ($CreateTestVM) {
            Write-Log 'Creating Hyper-V test VM'
            $vm = "SAROS-$(Get-Date -Format 'yyyyMMdd-HHmm')"; $vd = "$bp\VM"
            New-VM -Name $vm -NewVHDPath "$vd\$vm.vhdx" -NewVHDSizeBytes 64GB -MemoryStartupBytes 4GB -Path "$vd\VMs\$vm" -Generation 2
            Set-VMMemory $vm -DynamicMemoryEnabled $false; Set-VMProcessor $vm -Count 2 -Confirm:$false
            Set-VMKeyProtector $vm -NewLocalKeyProtector; Enable-VMTPM $vm -Confirm:$false
            Add-VMDvdDrive $vm -Path "$bp\$outISO"; Set-VMFirmware $vm -FirstBootDevice (Get-VMDvdDrive $vm)
            Set-VMHost -EnableEnhancedSessionMode $false; vmconnect $env:COMPUTERNAME $vm; Start-VM $vm
            Start-Sleep 5; Add-Type -AssemblyName System.Windows.Forms; [System.Windows.Forms.SendKeys]::SendWait('{ENTER}')
        }
    }

    Write-Step 12 $tot 'Complete'
    Write-Banner 'SAROS BUILD FINISHED'
    if ($ot -eq 'USB') { Write-Host '  USB ready. Boot target device (F12).' -ForegroundColor Green }
    else { Write-Host "  ISO: $bp\$outISO" -ForegroundColor Green }
    Write-Host "  Log: $($script:LogFile)" -ForegroundColor DarkGray
    Write-Host "  Elapsed: $((Get-Date).Subtract($script:StartTime).ToString('hh\:mm\:ss'))" -ForegroundColor DarkGray
    Write-Host ''
}

#endregion

try {
    if ($ManageVMs) {
        if (-not $script:OnWindows) { throw 'VM management requires Windows.' }
        Invoke-VMManager; return
    }
    if ($AnswerFileOnly) {
        Write-Banner "SAROS v$($script:Ver) — Answer file only"
        Write-Log "Platform: $($script:Platform) — answer file mode"
        $int = -not $Silent
        $ed = $Edition ?? ($int ? (Read-Choice 'Edition' @('Pro','Enterprise') 'Pro') : $null); $edK = ($ed -in 'Enterprise','ENT') ? 'ENT' : 'PRO'
        $lang = $Language; if (!$lang -and $int) { $lang = ($script:Locales | Where-Object N -EQ (Read-Searchable 'Language' (($script:Locales|Sort-Object N).N) 'English (United Kingdom)')).L }
        $lr = $script:Locales | Where-Object L -EQ $lang; if (!$lr) { throw "Unknown locale: $lang" }
        $tz = $TimeZone; if (!$tz -and $int) { $tzD=$script:TZList|ForEach-Object{($_ -split '\|')[1]}; $tz=($script:TZList|Where-Object{($_ -split '\|')[1] -eq (Read-Searchable 'Timezone' $tzD '(UTC) Dublin - Edinburgh - Lisbon - London')}|ForEach-Object{($_ -split '\|')[0]}) }
        $pt = $PAWType ?? ($int ? (Read-Choice 'PAW type' @('BOOTSTRAP','CLOUD') 'BOOTSTRAP') : 'BOOTSTRAP')
        $d = $BuildPath ?? ($int ? (Read-FolderPath 'Output folder') : $null); New-Item $d -ItemType Directory -Force -EA SilentlyContinue | Out-Null
        New-AnswerFile -Lang $lr.L -KB $lr.K -TZ $tz -Key $script:KMSKeys[$edK] -Ed $edK -Type $pt -Dir $d
        Write-Host "  Created: $(Join-Path $d 'autounattend.xml')" -ForegroundColor Green; return
    }
    Start-SAROSBuild
}
catch {
    Write-Log "FATAL: $_" -Lvl Error
    Write-Log $_.ScriptStackTrace -Lvl Error
    Write-Host "`n  FATAL: $_" -ForegroundColor Red
    Write-Host "  $($_.ScriptStackTrace)" -ForegroundColor DarkRed
    Write-Host "  Log: $($script:LogFile)" -ForegroundColor DarkGray
    exit 1
}
finally { Invoke-Cleanup }
